INSERT INTO public."News" ("id", "cityId", "title", "content", "imageUrl", "source", "isPublished", "createdAt") VALUES ('cmp8dtxc40026mavt8x0ttj9j', 'cmp8dtxb70000mavt7q4w47pi', 'Choutuppal Municipality Approves New Road Widening Project', 'The Choutuppal Municipality has approved a ₹15 crore road widening project for the Main Road stretch from Bus Stand to Highway Junction. The project is expected to be completed within 18 months and will ease traffic congestion in the town center. Local businesses have welcomed the move while requesting minimal disruption during construction.', NULL, 'Telangana Today', TRUE, '2026-05-16T13:28:49.157Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."News" ("id", "cityId", "title", "content", "imageUrl", "source", "isPublished", "createdAt") VALUES ('cmp8dtxc50028mavt2bdir5ab', 'cmp8dtxb70000mavt7q4w47pi', 'New Water Supply Scheme to Benefit 10,000 Households', 'The state government has sanctioned a new water supply scheme for Choutuppal under the Mission Bhagiratha program. The scheme will provide clean drinking water to over 10,000 households in the town and surrounding areas. Pipeline laying work has already begun and is expected to be completed by March next year.', 'https://images.unsplash.com/photo-1548839140-29a749e1cf4d?w=800', 'Eenadu', TRUE, '2026-05-16T13:28:49.157Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."News" ("id", "cityId", "title", "content", "imageUrl", "source", "isPublished", "createdAt") VALUES ('cmp8dtxc6002amavtg0xak5yv', 'cmp8dtxb70000mavt7q4w47pi', 'Choutuppal RDO Office Inaugurates Digital Services Center', 'The RDO office in Choutuppal has inaugurated a new digital services center that will allow citizens to access various government services online. Services include land records, certificates, and pension applications. The center is equipped with 20 computers and trained staff to assist the public.', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800', 'Namaste Telangana', TRUE, '2026-05-16T13:28:49.158Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."News" ("id", "cityId", "title", "content", "imageUrl", "source", "isPublished", "createdAt") VALUES ('cmp8dtxc6002cmavtuydsu4tx', 'cmp8dtxb70000mavt7q4w47pi', 'Annual Choutuppal Jatara Festival Draws Record Crowds', 'The annual Choutuppal Jatara festival celebrated at the ancient Sri Rama Temple drew record crowds this year with over 50,000 devotees attending the three-day event. The festival featured cultural programs, traditional dances, and a grand procession. Local authorities made elaborate arrangements for crowd management and security.', 'https://images.unsplash.com/photo-1544829099-b9a0c07fad1a?w=800', 'Sakshi', TRUE, '2026-05-16T13:28:49.159Z'::timestamp) ON CONFLICT DO NOTHING;